import * as React from 'react';
import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';

// import exifr from 'exifr';
// import SubHeader from '../SubHeader';



const Image = ({ item }) => {
	const fileName = item.match(/[A-Z]{1}[A-Za-z]+-\d{1,2}/g)[0];
	return (
		<>
			<Box component={'img'} src={item} flex={1} key={item} sx={{padding: '10px', backgroundColor: 'yellow'}}/>
			<Typography>
				{fileName}
			</Typography>
		</>
	)
}

function Gallery ({ name }) {
	const cache = {};

	function importAll(r) {
		r.keys().forEach((key) => (cache[key] = r(key)));
	};

	importAll(require.context('../assets/collections', false, /\.jpg/));
	const images = Object.entries(cache).map(module => module[1]);

	return (
		<Box
			display='flex'
			flexDirection='column'
			justifyContent='center'
			gap={2}
			sx={{
				margin: {
					// top | left and right | bottom
					// appbar 56px
					xs: '0px 30px 0px',
					sm: '0px 150px 0px',
					md: '0px 150px 0px',
					lg: '0px 400px 0px',
					xl: '0px 450px 0px',
				},
				// backgroundColor: {
				// 	xs: 'red',
				// 	sm: 'yellow',
				// 	md: 'grey',
				// 	lg: 'blue',
				// 	xl: 'green'
				// }
			}}
		>
			{
				images.map((item) => (
					item.includes(name) ?
					// <Box component={'img'} src={item} flex={1} key={item}/> :
					<Image item={item} /> :
					null
				))
			}
		</Box>
	)
}

export default Gallery;
